void main() {
  var capitals = <String, String>{
    'USA': 'Washington, DC',
    'France': 'Paris',
    'Japan': 'Tokyo',
    'India': 'New Delhi',
  };

  capitals['UK'] = 'London';
  capitals['France'] = 'Lyon'; // Update

  print('Capital of Japan: ${capitals['Japan']}');
  print('Has Germany: ${capitals.containsKey('Germany')}');

  capitals.forEach((country, capital) {
    print('$country -> $capital');
  });

  var upperKeys = capitals.keys.map((k) => k.toUpperCase()).toList();
  print('Countries: $upperKeys');
}
